$function$

CREATE OR REPLACE FUNCTION public.validate_lms_course_modify()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_is_admin BOOLEAN;
BEGIN
    -- Check if Admin
    SELECT EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = auth.uid() AND r.code = 'admin'
    ) INTO v_is_admin;

    IF v_is_admin THEN
        RETURN NEW;
    END IF;

    -- Check if Instructor
    IF NEW.instructor_id IS NOT NULL THEN
        IF NOT EXISTS (
            SELECT 1 FROM staff s
            WHERE s.id = NEW.instructor_id
              AND s.person_id = (SELECT person_id FROM users WHERE id = auth.uid())
        ) THEN
            RAISE EXCEPTION 'Unauthorized: Only the assigned Instructor or Admin can modify this course';
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

